import { readFileSync } from 'node:fs';
const footer=readFileSync('apps/liora/src/tui/components/chrome/footer.ts','utf8');
const web=readFileSync('packages/agent-core/src/tools/builtin/web/web-search.ts','utf8');
const search=readFileSync('packages/agent-core/src/tools/builtin/collaboration/search-skill.ts','utf8');
const c7=readFileSync('packages/agent-core/src/tools/providers/context7.ts','utf8');
const fails=[];
if (!footer.includes('formatZdrFooterBadge')) fails.push('zdr');
if (!footer.includes('formatOfficeFooterBadge')) fails.push('office');
if (!footer.includes('formatWebFooterBadge')) fails.push('web');
if (!web.includes('limit: args.limit ?? 3')) fails.push('web3');
if (!search.includes('Word docx report')) fails.push('office-hint');
if (!c7.includes('CONTEXT7_RESOLVE_MAX_MATCHES = 8')) fails.push('c7-resolve-cap');
if (!c7.includes('CONTEXT7_DOCS_TEXT_MAX_CHARS = 12_000')) fails.push('c7-docs-cap');
if (fails.length){console.error(fails.join(',')); process.exit(1);} console.log('beginner-zero-config-source-ok');
